// npm install --save-dev npm-check-updates

const { exec } = require('child_process');

function generatePackageLock() {
  exec('npm install', (error, stdout, stderr) => {
    if (error) {
      console.error(`Error generating package-lock.json: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`Stderr: ${stderr}`);
      return;
    }
    console.log(`package-lock.json generated successfully.`);
  });
}

function updateDependencies() {
  exec('npx npm-check-updates -u', (error, stdout, stderr) => {
    if (error) {
      console.error(`Error updating dependencies: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`Stderr: ${stderr}`);
      return;
    }
    console.log('Dependencies updated. Please run `npm install` to update package-lock.json.');
  });
}

function checkForUpdates() {
  exec('npx npm-check-updates', (error, stdout, stderr) => {
    if (error) {
      console.error(`Error checking for updates: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`Stderr: ${stderr}`);
      return;
    }
    console.log('Current dependency status:\n' + stdout);
  });
}

// Example usage:
generatePackageLock(); // Generates package-lock.json
updateDependencies();   // Updates dependencies and prompts to run npm install
checkForUpdates();      // Checks for available updates without modifying package.json